use std::collections::VecDeque;

fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut count = 0;
    for i in 0..m {
        for j in 0..n {
            if grid[i][j] > 0 {
                let mut q = VecDeque::new();
                let mut sum = grid[i][j];
                grid[i][j] = 0;
                q.push_back((i, j));
                while let Some((x, y)) = q.pop_front() {
                    let directions = [(-1, 0), (0, -1), (1, 0), (0, 1)];
                    for (dx, dy) in directions.iter() {
                        let nx = x as i32 + *dx;
                        let ny = y as i32 + *dy;
                        if nx >= 0 && nx < m as i32 && ny >= 0 && ny < n as i32 {
                            let nx_usize = nx as usize;
                            let ny_usize = ny as usize;
                            if grid[nx_usize][ny_usize] > 0 {
                                grid[nx_usize][ny_usize] = 0;
                                sum += grid[nx_usize][ny_usize];
                                q.push_back((nx_usize, ny_usize));
                            }
                        }
                    }
                }
                if sum % k == 0 {
                    count += 1;
                }
            }
        }
    }
    count
}
